// TemplateTabTypes.ets
//
// Shared tab-level types for scaffold components that should not depend on
// controller or page implementation files.
//
// Agent rules:
// - Keep TabId stable unless the app's primary tab model changes.
// - Update Index.ets and BottomTabBar.ets together when changing tab ids.
//
// Usage:
// - Add lightweight tab/navigation unions here when multiple scaffold files
// - need the same tab contract.
export type TabId =
  | 'tab-home'
  | 'tab-explore'
  | 'tab-orders'
  | 'tab-rewards';
===== common/SvgIcon.ets =====
// TemplateSvgIcon.ets
//
// A model-friendly icon entry template for scaffolded HarmonyOS apps.
//
// Agent rules:
// - Keep the exported struct name as SvgIcon.
// - Keep the public API stable: variant, iconSize, color, and strokeWidth.
// - Prefer updating fileNameForVariant() and the matching rawfile assets instead of
// - hardcoding resource paths in page-level components.
// - Keep variant names generic so scaffold components are not tied to one product domain.
//
// Usage:
// - Replace the default rawfile mappings with your real icon assets.
