    "spin-wheel": { "source": ["wheel-spin-trigger"], "description": "Trigger wheel animation and compute a dish result." },
    "accept-result": { "source": ["wheel-accept-button"], "description": "Accept the wheel result and optionally log it." },
    "retry-spin": { "source": ["wheel-retry-button"], "description": "Spin the wheel again." },
