{
  "uiTreePath": ".arkpilot/designs/ui-tree.json",
  "dataModel": {
    "entities": {
      "Dish": {
        "fields": ["id", "name", "cuisine", "tags", "ingredients", "moods", "mealTimes", "cookMinutes"],
        "notes": "Static bundled dish record. id is stable slug."
      },
      "Tag": "enum-ish: 暖胃|快手|清淡|辣|健康|治愈系 (display label + color token)",
      "CheckInItem": {
        "fields": ["id", "dateKey", "mealType", "dishName", "note", "timeLabel"],
        "notes": "Persisted user record. dateKey = yyyy-mm-dd. id = timestamp-based string."
      },
      "FridgeState": ["ingredients: string[] (persisted)", "matchedDishes: MatchedDish[] (computed)"],
      "MatchedDish": ["dishId", "matchedCount", "totalCount", "missing: string[]", "fullyMatched: boolean"],
      "WheelResult": ["dishId", "name", "tags: string[]"],
      "ShareCardData": ["title", "subtitle", "caption", "theme: enum"]
    },
    "settingsFormState": {
      "cuisinePreference": "string[] persisted (中餐|西餐|日料|韩餐|东南亚)",
      "dietaryRestriction": "string[] persisted (素食|不吃辣|少盐|无麸质)",
      "moodFilter": "string|null (想吃爽的|清淡一点|快速搞定|来点辣的)",
      "timeFilter": "string|null (早餐|午餐|晚餐|宵夜)"
    },
    "computedState": {
      "greeting": "time-of-day greeting string (早上好/中午好/下午好/晚上好 + 今天想吃点什么？)",
      "lastResult": "WheelResult|null persisted",
      "weekSummary": "{count:number, streakDays:number} computed from check-ins",
      "todayDate": "M月D日 星期X formatted string"
    },
    "persistenceFields": [
      "fridge.ingredients",
      "checkins (all CheckInItem records)",
      "cuisinePreference",
      "dietaryRestriction",
      "lastResult",
      "share.caption / share.theme (session-tolerant)"
    ]
  },
  "services": {
    "StorageService": {
      "boundary": "preferences-backed key/value persistence (@kit.ArkData preferences)",
      "keys": ["fridge_ingredients", "checkins", "cuisine_pref", "dietary_pref", "last_result", "share_caption", "share_theme"],
      "api": ["loadAll(): Promise<PersistedData>", "saveJSON(key, json): Promise<void>", "clearAll(): Promise<void>"]
    },
    "DishLibrary": {
      "boundary": "static in-bundle dish list (TS constant). No network, no user seed.",
      "api": ["ALL: Dish[]", "byId(id): Dish|undefined"]
    },
    "RecommendService": {
      "boundary": "pure function: ingredient matching + mood/time/preference filtering",
      "api": [
        "matchByIngredients(dishes, ingredients): MatchedDish[]",
        "filterForWheel(dishes, {mood, time, cuisine, dietary}): Dish[]"
      ]
    },
    "WheelService": {
      "boundary": "deterministic random pick over filtered candidates; returns angle for animation",
      "api": ["pick(candidates: Dish[], segments: number): {dish: Dish, finalAngle: number}"]
    },
    "ShareService": {
      "boundary": "build share payload + trigger system share / save image via componentSnapshot + image packer",
      "api": [
        "buildPayload(card: ShareCardData): string",
        "shareToSystem(text: string): Promise<void>  (systemShare or pasteboard fallback)",
        "saveImage(pixelMap): Promise<string>"
      ]
    }
  },
  "stateMachine": {
    "wheel": {
      "states": ["idle", "spinning", "result"],
      "transitions": [
        { "from": "idle|result", "on": "spin-wheel", "to": "spinning", "effect": "compute pick; animate rotate" },
        { "from": "spinning", "on": "animationEnd", "to": "result", "effect": "reveal dish; persist lastResult" },
        { "from": "result", "on": "retry-spin", "to": "spinning" },
        { "from": "result", "on": "accept-result", "to": "idle", "effect": "return to home / set lastResult" }
      ]
    },
    "fridge": {
      "states": ["empty", "matching", "populated", "no-match"],
      "transitions": [
        { "on": "confirm-add-ingredient", "to": "populated|matching" },
        { "on": "remove-ingredient|clear-ingredients", "to": "empty|populated" },
        { "computed": "matchedDishes empty => no-match" }
      ]
    },
    "checkinSheet": {
      "states": ["closed", "open"],
      "transitions": [
        { "on": "open-checkin-sheet", "to": "open" },
        { "on": "save-checkin|close-checkin-sheet", "to": "closed" }
      ]
    }
  },
  "interactionFlows": [
    {
      "name": "spin-from-home",
      "trigger": "home-spin-button",
      "steps": ["open-wheel", "spin-wheel", "compute pick from filtered candidates", "animate to finalAngle", "reveal result name+tags", "persist lastResult"],
      "expectedState": "wheel/result, home lastResult updated",
      "errorPath": "no candidates after filter => show friendly empty notice, still allow retry"
    },
    {
      "name": "accept-and-checkin",
      "trigger": "wheel-accept-button",
      "steps": ["set lastResult", "open-checkin-sheet pre-filled with result name", "save-checkin appends CheckInItem for today"],
      "expectedState": "checkin added today, sheet closed"
    },
    {
      "name": "fridge-recommend",
      "trigger": "fridge-add-button",
      "steps": ["read input", "confirm-add-ingredient", "persist ingredients", "recompute matchedDishes via RecommendService.matchByIngredients"],
      "expectedState": "matchedDishList updated; fridge-dish-{id} per match"
    },
    {
      "name": "save-checkin",
      "trigger": "checkin-sheet-save-button",
      "steps": ["validate dishName non-empty", "append CheckInItem {dateKey:today, mealType, dishName, note, timeLabel:now}", "persist checkins", "close sheet"],
      "errorPath": "empty dishName => inline validation hint, do not save"
    },
    {
      "name": "share-card",
      "trigger": "share-system-button / share-save-image-button",
      "steps": ["read ShareCardData {title:lastResult.name, caption, theme}", "edit-share-caption updates caption", "set-share-theme updates theme gradient", "share-to-system => systemShare/pasteboard", "save-card-image => componentSnapshot + image packer to sandbox/cache"],
      "expectedState": "share payload delivered or image saved; feedback toast"
    },
    {
      "name": "profile-toggle",
      "trigger": "profile-cuisine-preference / profile-dietary-restriction",
      "steps": ["toggle item in persisted array", "recompute wheel candidate filter"],
      "expectedState": "preference persisted, chip active state toggled"
    },
    {
      "name": "clear-history",
      "trigger": "profile-clear-history-button",
      "steps": ["confirm dialog", "StorageService.clearAll()", "reset in-memory state"],
      "expectedState": "empty first-run state"
    },
    {
      "name": "export-data",
      "trigger": "profile-export-data-button",
      "steps": ["serialize persisted data to JSON text", "copy to pasteboard / share"],
      "expectedState": "feedback toast with exported summary"
    }
  ],
  "testTargets": {
    "bottom-tab-bar": ["tab-home", "tab-fridge", "tab-checkin", "tab-profile"],
    "home": ["home-greeting", "home-spin-button", "home-filter-mood", "home-filter-time", "home-last-result-card", "home-no-result-yet", "home-quick-checkin-button"],
    "wheel": ["wheel-back-button", "wheel-canvas", "wheel-spin-trigger", "wheel-result-name", "wheel-result-tags", "wheel-accept-button", "wheel-retry-button", "wheel-filter-chip-group"],
    "fridge": ["fridge-ingredient-input", "fridge-add-button", "fridge-ingredient-list", "fridge-remove-button", "fridge-matched-dish-list", "fridge-clear-all-button", "fridge-empty-state", "fridge-no-match-state"],
    "checkin": ["checkin-today-date", "checkin-add-button", "checkin-timeline-list", "checkin-week-summary", "checkin-empty-state", "checkin-sheet-dish-name", "checkin-sheet-note", "checkin-sheet-meal-type", "checkin-sheet-save-button", "checkin-sheet-cancel-button"],
    "share": ["share-back-button", "share-card-preview", "share-card-title", "share-card-caption", "share-card-theme-picker", "share-system-button", "share-save-image-button"],
    "profile": ["profile-cuisine-preference", "profile-dietary-restriction", "profile-clear-history-button", "profile-export-data-button"]
  },
  "changeRequests": []
}

