// Domain models for 今天吃什么.
// Plain entities shared by services, view-model, and pages.

export type MealType = '早餐' | '午餐' | '晚餐' | '加餐';

export type MoodKey = '想吃爽的' | '清淡一点' | '快速搞定' | '来点辣的';

export type TimeKey = '早餐' | '午餐' | '晚餐' | '宵夜';

export type WheelState = 'idle' | 'spinning' | 'result';

export type ShareTheme = 'coral' | 'golden' | 'sage' | 'dark';

export class Dish {
  id: string;
  name: string;
  cuisine: string;
  tags: string[];
  ingredients: string[];
  moods: string[];
  mealTimes: string[];
  cookMinutes: number;
  hasMeat: boolean;

  constructor(
    id: string,
    name: string,
    cuisine: string,
    tags: string[],
    ingredients: string[],
    moods: string[],
    mealTimes: string[],
    cookMinutes: number,
    hasMeat: boolean,
  ) {
    this.id = id;
    this.name = name;
    this.cuisine = cuisine;
    this.tags = tags;
    this.ingredients = ingredients;
    this.moods = moods;
    this.mealTimes = mealTimes;
    this.cookMinutes = cookMinutes;
    this.hasMeat = hasMeat;
  }
}

export class MatchedDish {
  dish: Dish;
  matchedCount: number;
  totalCount: number;
  missing: string[];
  fullyMatched: boolean;

  constructor(dish: Dish, matchedCount: number, totalCount: number, missing: string[], fullyMatched: boolean) {
    this.dish = dish;
    this.matchedCount = matchedCount;
    this.totalCount = totalCount;
    this.missing = missing;
    this.fullyMatched = fullyMatched;
  }
}

export class CheckInItem {
  id: string;
  dateKey: string;
  mealType: MealType;
  dishName: string;
  note: string;
  timeLabel: string;

  constructor(id: string, dateKey: string, mealType: MealType, dishName: string, note: string, timeLabel: string) {
    this.id = id;
    this.dateKey = dateKey;
    this.mealType = mealType;
    this.dishName = dishName;
    this.note = note;
    this.timeLabel = timeLabel;
  }
}

export class WheelResult {
  dishId: string;
  name: string;
  tags: string[];

  constructor(dishId: string, name: string, tags: string[]) {
    this.dishId = dishId;
    this.name = name;
    this.tags = tags;
  }
}

export interface WheelSpinResult {
  dish: Dish;
  finalAngle: number;
}

export interface WeekSummary {
  count: number;
  streakDays: number;
}

