// Pure recommendation helpers: ingredient matching and wheel filtering.
import { Dish, MatchedDish } from '../model/Models';

export interface WheelFilter {
  mood: string | null;
  time: string | null;
  cuisine: string[];
  dietary: string[];
}

export class RecommendService {
  // Match dishes against current ingredients. Returns matches with >=1 hit,
  // sorted by matchedCount desc then fewer missing.
  static matchByIngredients(dishes: Dish[], ingredients: string[]): MatchedDish[] {
    const cleaned = ingredients.map((s) => s.trim()).filter((s) => s.length > 0);
    if (cleaned.length === 0) {
      return [];
    }
    const lower = cleaned.map((s) => s.toLowerCase());
    const out: MatchedDish[] = [];
    for (const dish of dishes) {
      let matched = 0;
      const missing: string[] = [];
      for (const ing of dish.ingredients) {
        if (lower.includes(ing.toLowerCase())) {
          matched++;
        } else {
          missing.push(ing);
        }
      }
      if (matched > 0) {
        out.push(new MatchedDish(dish, matched, dish.ingredients.length, missing, missing.length === 0));
      }
    }
    out.sort((a, b) => {
      if (b.matchedCount !== a.matchedCount) {
        return b.matchedCount - a.matchedCount;
      }
      return a.missing.length - b.missing.length;
    });
    return out;
  }

  // Filter the dish pool by mood/time/cuisine/dietary for the wheel.
  static filterForWheel(dishes: Dish[], filter: WheelFilter): Dish[] {
    let out = dishes;
    if (filter.cuisine.length > 0) {
      out = out.filter((d) => filter.cuisine.includes(d.cuisine));
    }
    if (filter.dietary.includes('素食')) {
      out = out.filter((d) => !d.hasMeat);
    }
    if (filter.dietary.includes('不吃辣')) {
      out = out.filter((d) => !d.tags.includes('辣'));
    }
    if (filter.mood) {
      out = out.filter((d) => d.moods.includes(filter.mood as string));
    }
    if (filter.time) {
      out = out.filter((d) => d.mealTimes.includes(filter.time as string));
    }
    return out;
  }
}

