  // Fridge
  @Trace ingredients: string[] = [];
  @Trace matchedDishes: MatchedDish[] = [];

  // Check-in
  @Trace checkins: CheckInItem[] = [];

  // Preferences
  @Trace cuisinePref: string[] = ['中餐', '西餐'];
  @Trace dietaryPref: string[] = ['少盐'];

  // Filters (shared by Home + Wheel)
  @Trace moodFilter: MoodKey | null = '想吃爽的';
  @Trace timeFilter: TimeKey | null = '早餐';

  // Wheel
  @Trace wheelState: WheelState = 'idle';
  @Trace wheelResultName: string = '';
  @Trace wheelResultTags: string[] = [];
  @Trace lastResult: WheelResult | null = null;

  // Check-in sheet
  @Trace sheetOpen: boolean = false;
  @Trace sheetMealType: MealType = '午餐';
  @Trace sheetDish: string = '';
  @Trace sheetNote: string = '';
  @Trace sheetPrefill: boolean = false;
  @Trace sheetError: string = '';

  // Share
  @Trace shareCaption: string = '今天运气不错，转盘选中了最爱吃的！';
  @Trace shareTheme: ShareTheme = 'coral';

  // Feedback
  @Trace toast: string = '';

  private context: common.Context | null = null;
  private ready: boolean = false;

  // ---- Lifecycle ----
  async init(context: common.Context): Promise<void> {
    this.context = context;
    await StorageService.init(context);
    const ingredients = await StorageService.readJson<string[]>(StorageService.KEYS.fridge, []);
    this.ingredients = ingredients;
    const checkins = await StorageService.readJson<CheckInItem[]>(StorageService.KEYS.checkins, []);
    this.checkins = checkins;
    this.cuisinePref = await StorageService.readJson<string[]>(StorageService.KEYS.cuisine, ['中餐', '西餐']);
    this.dietaryPref = await StorageService.readJson<string[]>(StorageService.KEYS.dietary, ['少盐']);
    this.lastResult = await StorageService.readJson<WheelResult | null>(StorageService.KEYS.lastResult, null);
    this.shareCaption = await StorageService.readString(StorageService.KEYS.shareCaption, this.shareCaption);
    const persistedTheme = await StorageService.readString(StorageService.KEYS.shareTheme, 'coral');
    this.shareTheme = (persistedTheme as ShareTheme);
    this.recomputeMatches();
    this.ready = true;
  }

  // ---- Computed (plain getters; read inside build()) ----
  get greeting(): string {
    const h = new Date().getHours();
    if (h < 6) {
      return '夜深了，今天想吃点什么？';
    } else if (h < 11) {
      return '早上好，今天想吃点什么？';
    } else if (h < 14) {
      return '中午好，今天想吃点什么？';
    } else if (h < 18) {
      return '下午好，今天想吃点什么？';
    }
    return '晚上好，今天想吃点什么？';
  }

  get todayDate(): string {
    const d = new Date();
    const week = ['日', '一', '二', '三', '四', '五', '六'];
    return `${d.getMonth() + 1}月${d.getDate()}日 星期${week[d.getDay()]}`;
  }

  private todayKey(): string {
    const d = new Date();
    const m = `${d.getMonth() + 1}`.padStart(2, '0');
    const day = `${d.getDate()}`.padStart(2, '0');
    return `${d.getFullYear()}-${m}-${day}`;
  }

  get todayCheckins(): CheckInItem[] {
    const key = this.todayKey();
    return this.checkins.filter((c) => c.dateKey === key);
  }

  get weekSummary(): WeekSummary {
    const now = new Date();
    const count = this.checkins.filter((c) => {
      const diff = (now.getTime() - new Date(c.dateKey).getTime()) / (24 * 3600 * 1000);
      return diff >= 0 && diff < 7;
    }).length;
    // streak: consecutive days up to today with >=1 check-in
    let streak = 0;
    for (let i = 0; i < 30; i++) {
      const d = new Date(now.getTime() - i * 24 * 3600 * 1000);
      const m = `${d.getMonth() + 1}`.padStart(2, '0');
      const day = `${d.getDate()}`.padStart(2, '0');
      const key = `${d.getFullYear()}-${m}-${day}`;
      const has = this.checkins.some((c) => c.dateKey === key);
      if (has) {
        streak++;
      } else if (i === 0) {
        // today empty does not break streak yet
        continue;
      } else {
        break;
      }
    }
    return { count, streakDays: streak };
  }

  // ---- Fridge ----
  addIngredient(raw: string): void {
    const name = raw.trim();
    if (name.length === 0) {
      return;
    }
    if (this.ingredients.includes(name)) {
      return;
    }
    this.ingredients = [...this.ingredients, name];
    this.persistIngredients();
    this.recomputeMatches();
  }

  removeIngredient(name: string): void {
    this.ingredients = this.ingredients.filter((i) => i !== name);
    this.persistIngredients();
    this.recomputeMatches();
  }

  clearIngredients(): void {
    this.ingredients = [];
    this.persistIngredients();
    this.recomputeMatches();
  }

  private persistIngredients(): void {
    StorageService.writeJson(StorageService.KEYS.fridge, this.ingredients).catch((e: Object) => {
      hilog.error(DOMAIN, TAG, 'persist ingredients failed: %{public}s', `${e}`);
    });
  }

  recomputeMatches(): void {
    this.matchedDishes = RecommendService.matchByIngredients(DishLibrary.ALL, this.ingredients);
  }

  // ---- Filters ----
  setMood(value: MoodKey): void {
    this.moodFilter = this.moodFilter === value ? null : value;
  }

  setTime(value: TimeKey): void {
    this.timeFilter = this.timeFilter === value ? null : value;
  }

  toggleWheelFilter(label: string): void {
    // Wheel quick-filter chips mirror mood semantics.
    if (label === '清淡') {
      this.setMood('清淡一点');
    } else if (label === '辣的') {
      this.setMood('来点辣的');
    } else if (label === '快手') {
      this.setMood('快速搞定');
    } else if (label === '治愈系' || label === '健康') {
      this.moodFilter = this.moodFilter === '想吃爽的' ? null : '想吃爽的';
    }
  }

  // ---- Wheel ----
  wheelFilter(): WheelFilter {
    return {
      mood: this.moodFilter,
      time: this.timeFilter,
      cuisine: this.cuisinePref,
      dietary: this.dietaryPref,
    };
  }

  wheelCandidates(): Dish[] {
    const filtered = RecommendService.filterForWheel(DishLibrary.ALL, this.wheelFilter());
    return filtered.length > 0 ? filtered : DishLibrary.ALL;
  }

  wheelSegmentLabels(): string[] {
    return WheelService.segmentLabels(this.wheelCandidates());
  }

  // Compute a spin without committing; the page animates then calls commitSpin.
  computeSpin(): WheelSpinResult {
    const candidates = this.wheelCandidates();
    return WheelService.pick(candidates);
  }

  commitSpin(result: WheelSpinResult): void {
    this.wheelState = 'result';
    this.wheelResultName = result.dish.name;
    this.wheelResultTags = result.dish.tags;
    this.lastResult = new WheelResult(result.dish.id, result.dish.name, result.dish.tags);
    StorageService.writeJson(StorageService.KEYS.lastResult, this.lastResult as WheelResult).catch((e: Object) => {
      hilog.error(DOMAIN, TAG, 'persist lastResult failed: %{public}s', `${e}`);
    });
  }

  setWheelState(state: WheelState): void {
    this.wheelState = state;
  }

  // ---- Check-in sheet ----
  openSheet(prefillDish: string = ''): void {
    this.sheetError = '';
    this.sheetPrefill = prefillDish.length > 0;
    this.sheetDish = prefillDish;
    this.sheetNote = '';
    this.sheetMealType = this.guessMealType();
    this.sheetOpen = true;
  }

  closeSheet(): void {
    this.sheetOpen = false;
    this.sheetError = '';
  }

  setSheetDish(v: string): void {
    this.sheetDish = v;
    if (v.length > 0) {
      this.sheetError = '';
    }
  }

  setSheetNote(v: string): void {
    this.sheetNote = v;
  }

  setSheetMealType(v: MealType): void {
    this.sheetMealType = v;
  }

  saveCheckin(): boolean {
    const name = this.sheetDish.trim();
    if (name.length === 0) {
      this.sheetError = '请填写吃了什么';
      return false;
    }
    const now = new Date();
    const hh = `${now.getHours()}`.padStart(2, '0');
    const mm = `${now.getMinutes()}`.padStart(2, '0');
    const item = new CheckInItem(
      `ci_${now.getTime()}`,
      this.todayKey(),
      this.sheetMealType,
      name,
      this.sheetNote.trim(),
      `${hh}:${mm}`,
    );
    this.checkins = [...this.checkins, item];
    StorageService.writeJson(StorageService.KEYS.checkins, this.checkins).catch((e: Object) => {
      hilog.error(DOMAIN, TAG, 'persist checkins failed: %{public}s', `${e}`);
    });
    this.closeSheet();
    this.showToast('已记录这一餐');
    return true;
  }

  private guessMealType(): MealType {
    const h = new Date().getHours();
    if (h < 10) {
      return '早餐';
    } else if (h < 14) {
      return '午餐';
    } else if (h < 21) {
      return '晚餐';
    }
    return '加餐';
  }

  // ---- Preferences ----
  toggleCuisine(value: string): void {
    if (this.cuisinePref.includes(value)) {
      this.cuisinePref = this.cuisinePref.filter((c) => c !== value);
    } else {
      this.cuisinePref = [...this.cuisinePref, value];
    }
    StorageService.writeJson(StorageService.KEYS.cuisine, this.cuisinePref).catch((e: Object) => {
      hilog.error(DOMAIN, TAG, 'persist cuisine failed: %{public}s', `${e}`);
    });
  }

  toggleDietary(value: string): void {
    if (this.dietaryPref.includes(value)) {
      this.dietaryPref = this.dietaryPref.filter((c) => c !== value);
    } else {
      this.dietaryPref = [...this.dietaryPref, value];
    }
    StorageService.writeJson(StorageService.KEYS.dietary, this.dietaryPref).catch((e: Object) => {
      hilog.error(DOMAIN, TAG, 'persist dietary failed: %{public}s', `${e}`);
    });
  }

  isDietaryActive(value: string): boolean {
    return this.dietaryPref.includes(value);
  }

  // ---- Share ----
  setShareCaption(v: string): void {
    this.shareCaption = v;
    StorageService.writeString(StorageService.KEYS.shareCaption, v).catch((e: Object) => {
      hilog.error(DOMAIN, TAG, 'persist caption failed: %{public}s', `${e}`);
    });
  }

  setShareTheme(t: ShareTheme): void {
    this.shareTheme = t;
    StorageService.writeString(StorageService.KEYS.shareTheme, t).catch((e: Object) => {
      hilog.error(DOMAIN, TAG, 'persist theme failed: %{public}s', `${e}`);
    });
  }

  get shareTitle(): string {
    return this.lastResult ? this.lastResult.name : '今天吃什么';
  }

  get shareSubtitle(): string {
    if (this.lastResult) {
      return `转盘替我决定了今天${this.guessMealTypeLabel()}`;
    }
    return '转一转，美味立刻有答案';
  }

  private guessMealTypeLabel(): string {
    const m = this.guessMealType();
    return m;
  }

  // ---- Data actions ----
  clearHistory(): void {
    this.checkins = [];
    this.ingredients = [];
    this.matchedDishes = [];
    this.lastResult = null;
    this.cuisinePref = [];
    this.dietaryPref = [];
    StorageService.clearAll().catch((e: Object) => {
      hilog.error(DOMAIN, TAG, 'clearAll failed: %{public}s', `${e}`);
    });
    this.showToast('已清空所有记录');
  }

  async exportData(): Promise<string> {
    const payload = {
      checkins: this.checkins,
      ingredients: this.ingredients,
      cuisinePref: this.cuisinePref,
      dietaryPref: this.dietaryPref,
      lastResult: this.lastResult,
    };
    return JSON.stringify(payload);
  }

  isReady(): boolean {
    return this.ready;
  }

  dietaryOptions(): string[] {
    return DIETARY_OPTIONS;
  }

  showToast(message: string): void {
    this.toast = message;
  }
}

