// Wheel spin logic: pick a dish from candidates and compute a final rotation
// angle that lands the chosen segment under the top pointer.
import { Dish, WheelSpinResult } from '../model/Models';

export class WheelService {
  static readonly SEGMENT_COUNT = 6;

  // Pick a candidate, map it onto one of SEGMENT_COUNT wheel slots, and compute
  // the absolute rotation that stops the chosen slot at the top (under pointer).
  // Spins at least 5 full turns plus the offset to the chosen slot.
  static pick(candidates: Dish[]): WheelSpinResult {
    const pool = candidates.length > 0 ? candidates : [];
    if (pool.length === 0) {
      throw new Error('No wheel candidates available');
    }
    const dish = pool[Math.floor(Math.random() * pool.length)];
    const slotIndex = WheelService.slotFor(dish.id, pool);
    const segmentAngle = 360 / WheelService.SEGMENT_COUNT;
    // Each slot center sits at slotIndex * segmentAngle (measured clockwise from top).
    // To bring that slot to the top we rotate the wheel by -slotCenter (mod 360),
    // plus several full turns.
    const targetWithinTurn = (360 - slotIndex * segmentAngle) % 360;
    const fullTurns = 5 + Math.floor(Math.random() * 2);
    const finalAngle = fullTurns * 360 + targetWithinTurn;
    return { dish, finalAngle };
  }

  // Deterministic slot index for a dish id across the pool, distributed over
  // SEGMENT_COUNT slots so repeated ids map predictably.
  static slotFor(id: string, pool: Dish[]): number {
    let hash = 0;
    for (let i = 0; i < id.length; i++) {
      hash = (hash * 31 + id.charCodeAt(i)) & 0x7fffffff;
    }
    return hash % WheelService.SEGMENT_COUNT;
  }

  // Up to SEGMENT_COUNT labels to render on the wheel face.
  static segmentLabels(candidates: Dish[]): string[] {
    const labels: string[] = [];
    for (let i = 0; i < WheelService.SEGMENT_COUNT; i++) {
      if (i < candidates.length) {
        labels.push(candidates[i].name);
      } else {
        labels.push('');
      }
    }
    return labels;
  }
}

