// Preferences-backed key/value persistence for 今天吃什么.
// Uses @kit.ArkData preferences. All structured values are stored as JSON strings.
import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';

export interface StorageKeys {
  fridge: string;
  checkins: string;
  cuisine: string;
  dietary: string;
  lastResult: string;
  shareCaption: string;
  shareTheme: string;
}

export class StorageService {
  private static store: preferences.Preferences | null = null;
  private static readonly STORE_NAME = 'eatwhat_store';

  static readonly KEYS: StorageKeys = {
    fridge: 'fridge_ingredients',
    checkins: 'checkins',
    cuisine: 'cuisine_pref',
    dietary: 'dietary_pref',
    lastResult: 'last_result',
    shareCaption: 'share_caption',
    shareTheme: 'share_theme',
  };

  static async init(context: common.Context): Promise<void> {
    if (StorageService.store) {
      return;
    }
    StorageService.store = await preferences.getPreferences(context, StorageService.STORE_NAME);
  }

  static async readJson<T>(key: string, fallback: T): Promise<T> {
    if (!StorageService.store) {
      return fallback;
    }
    const raw = await StorageService.store.get(key, '');
    if (typeof raw !== 'string' || raw.length === 0) {
      return fallback;
    }
    try {
      return JSON.parse(raw) as T;
    } catch (e) {
      return fallback;
    }
  }

  static async readString(key: string, fallback: string): Promise<string> {
    if (!StorageService.store) {
      return fallback;
    }
    const raw = await StorageService.store.get(key, fallback);
    return typeof raw === 'string' ? raw : fallback;
  }

  static async writeJson(key: string, value: Object): Promise<void> {
    if (!StorageService.store) {
      return;
    }
    await StorageService.store.put(key, JSON.stringify(value));
    await StorageService.store.flush();
  }

  static async writeString(key: string, value: string): Promise<void> {
    if (!StorageService.store) {
      return;
    }
    await StorageService.store.put(key, value);
    await StorageService.store.flush();
  }

  static async clearAll(): Promise<void> {
    if (!StorageService.store) {
      return;
    }
    const keys = Object.values(StorageService.KEYS);
    for (const k of keys) {
      await StorageService.store.delete(k);
    }
    await StorageService.store.flush();
  }
}

// Share helpers: build a text payload, deliver via system pasteboard, and
// pack a component snapshot PixelMap into a saved JPEG file.
// Pasteboard is used as the robust MVP share channel (documented fallback for
// the system share sheet, which requires additional controller wiring).
import { pasteboard } from '@ohos.pasteboard';
import { image } from '@kit.ImageKit';
import { fileIo as fs } from '@kit.CoreFileKit';
import { common } from '@kit.AbilityKit';

export interface ShareCardPayload {
  title: string;
  subtitle: string;
  caption: string;
}

export interface PackingOption {
  format: string;
  quality: number;
}

export class ShareService {
  static buildPayload(card: ShareCardPayload): string {
    const caption: string = card.caption.trim();
    const head: string = `今天吃什么 · ${card.title}`;
    const sub: string = card.subtitle.length > 0 ? card.subtitle : '';
    return caption.length > 0 ? `${head}\n${sub}\n${caption}` : `${head}\n${sub}`;
  }

  static async shareToSystem(card: ShareCardPayload): Promise<void> {
    const text: string = ShareService.buildPayload(card);
    const data = pasteboard.createData(pasteboard.MIMETYPE_TEXT_PLAIN, text);
    const systemPasteboard = pasteboard.getSystemPasteboard();
    await systemPasteboard.setData(data);
  }

  // Pack a snapshot PixelMap to JPEG under the app cache directory and return
  // the absolute file path. Returns '' on failure.
  static async saveImage(pixelMap: image.PixelMap, context: common.Context): Promise<string> {
    let filePath = '';
    try {
      const packer = image.createImagePacker();
      const buffer: ArrayBuffer = await packer.packToData(pixelMap, { format: 'image/jpeg', quality: 92 } as PackingOption);
      filePath = `${context.cacheDir}/share_${Date.now()}.jpg`;
      const file = fs.openSync(filePath, fs.OpenMode.READ_WRITE | fs.OpenMode.CREATE);
      try {
        fs.writeSync(file.fd, buffer);
      } finally {
        fs.closeSync(file);
      }
    } catch (e) {
      return '';
    }
    return filePath;
  }
}

