// Map a share theme to its gradient + on-card text colors.
export interface CardThemeStyle {
  gradient: LinearGradient;
  subtitleColor: string;
  captionBg: string;
  captionBorder: string;
  illusBg: string;
}

export function shareThemeStyle(theme: string): CardThemeStyle {
  if (theme === 'golden') {
    return {
      gradient: BrandGradient.golden,
      subtitleColor: 'rgba(61,43,31,0.85)',
      captionBg: 'rgba(255,255,255,0.55)',
