      subtitleColor: 'rgba(255,255,255,0.90)',
      captionBg: 'rgba(255,255,255,0.18)',
      captionBorder: 'rgba(255,255,255,0.28)',
      illusBg: 'rgba(255,255,255,0.16)',
    } as CardThemeStyle;
  }
  return {
    gradient: BrandGradient.coral,
    subtitleColor: 'rgba(255,255,255,0.90)',
    captionBg: 'rgba(255,255,255,0.20)',
    captionBorder: 'rgba(255,255,255,0.30)',
    illusBg: 'rgba(255,255,255,0.22)',
  } as CardThemeStyle;
}

