// TemplateBottomTabBar.ets
//
// A model-friendly BottomTabBar template for apps that use a fixed bottom tab shell.

input.content:
// Fixed bottom-tab bar for 今天吃什么. Stable public API: activeTab + onTap.
// Tab content (ids, labels, icon variants) is the only thing customized here;
// the layout hierarchy and contract stay aligned with Index.ets.
import { SvgIcon } from '../common/SvgIcon';
import { TabId } from '../common/TabTypes';
import { Theme } from '../common/Theme';

interface TabDescriptor {
  id: TabId;
  label: string;
  icon: string;
  iconActive: string;
}

const TABS: TabDescriptor[] = [
  { id: 'tab-home', label: '首页', icon: 'home', iconActive: 'homeActive' },
  { id: 'tab-fridge', label: '冰箱', icon: 'fridge', iconActive: 'fridgeActive' },
  { id: 'tab-checkin', label: '打卡', icon: 'checkin', iconActive: 'checkinActive' },
  { id: 'tab-profile', label: '我的', icon: 'profile', iconActive: 'profileActive' },
];

@Component
export struct BottomTabBar {
  @Prop activeTab: TabId;
  onTap: (tab: TabId) => void = () => {};

  build() {
    Row() {
      ForEach(TABS, (tab: TabDescriptor) => {
        Column() {
          SvgIcon({
            variant: this.activeTab === tab.id ? tab.iconActive : tab.icon,
            iconSize: 24,
          })
          Text(tab.label)
            .fontSize(11)
            .fontWeight(FontWeight.Medium)
            .fontColor(this.activeTab === tab.id ? Theme.coral : Theme.stone)
            .margin({ top: 4 })
        }
        .id(tab.id)
        .padding({ left: 12, right: 12, top: 6, bottom: 6 })
        .onClick(() => this.onTap(tab.id))
        .layoutWeight(1)
        .alignItems(HorizontalAlign.Center)
      }, (tab: TabDescriptor) => tab.id)
    }
    .width('100%')
    .height(Theme.bottomTabHeight)
    .padding({ bottom: 8 })
    .backgroundColor(Theme.tabBarBg)
    .border({ width: { top: 1 }, color: { top: Theme.borderFaint } })
    .justifyContent(FlexAlign.SpaceAround)
    .alignItems(VerticalAlign.Center)
  }
}

