// Small UI helpers (toasts) to avoid ad-hoc promptAction calls in pages.
import { promptAction } from '@kit.ArkUI';

export class UIUtil {
  static showToast(message: string): void {
    try {
      promptAction.showToast({
        message: message,
        duration: 2000,
        bottom: 120,
      });
    } catch (e) {
      // ignore toast failures
    }
  }
}

