// Home page — daily decision hub. Reproduces page-home-page.html.
import { AppViewModel } from '../viewmodel/AppViewModel';
import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { tagColor } from '../data/DishLibrary';
import { MoodKey, TimeKey } from '../model/Models';

const MOODS: string[] = ['想吃爽的', '清淡一点', '快速搞定', '来点辣的'];
const TIMES: string[] = ['早餐', '午餐', '晚餐', '宵夜'];

@Component
export struct HomePage {
  vm: AppViewModel;
  openWheel: () => void = () => {};
  openCheckin: (dish: string) => void = (_dish: string) => {};
  openShare: () => void = () => {};

  build() {
    Column() {
      // Header
      Column({ alignItems: HorizontalAlign.Start }) {
        Text(this.vm.greeting)
          .id('home-greeting')
          .fontSize(30)
          .fontWeight(FontWeight.Bold)
          .lineHeight(1.12)
          .fontColor(Theme.espresso)
        Text('让转盘帮你决定，或用冰箱里的食材发现新菜谱。')
          .fontSize(15)
          .fontColor(Theme.stone)
          .margin({ top: 6 })
      }
      .width('100%')
      .alignItems(HorizontalAlign.Start)
      .margin({ bottom: 22 })

      // Hero card
      Column() {
        Column() {
          SvgIcon({ variant: 'spinWheel', iconSize: 56 })
        }
        .width(108)
        .height(108)
        .borderRadius(54)
        .linearGradient(BrandGradient.coral)
        .justifyContent(FlexAlign.Center)
        .alignItems(HorizontalAlign.Center)
        .shadow(Theme.shadowFloat)
        .margin({ bottom: 16 })

        Text('今天吃什么？')
          .fontSize(22)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.espresso)
        Text('转一转，美味立刻有答案')
          .fontSize(15)
          .fontColor(Theme.stone)
          .margin({ top: 8, bottom: 20 })

        Button(this.openWheelLabel()) {
          Row() {
            SvgIcon({ variant: 'spin', iconSize: 20 })
            Text('开始转盘')
              .fontSize(16)
              .fontWeight(FontWeight.Medium)
              .fontColor('#FFFFFF')
              .margin({ left: 8 })
          }
        }
        .id('home-spin-button')
        .type(ButtonType.Capsule)
        .height(54)
        .padding({ left: 32, right: 32 })
        .linearGradient(BrandGradient.coral)
        .shadow(Theme.shadowFloat)
        .onClick(() => this.openWheel())
      }
      .width('100%')
      .padding(28)
      .borderRadius(Theme.radiusCardLarge)
      .backgroundColor(Theme.cardBg)
      .shadow(Theme.shadowFloat)
      .alignItems(HorizontalAlign.Center)
      .margin({ bottom: 20 })

      // Mood filter
      this.FilterSection('此刻心情', 'home-filter-mood', MOODS,
        (k: string) => this.vm.moodFilter === k,
        (k: string) => this.vm.setMood(k as MoodKey))

      // Time filter
      this.FilterSection('用餐时间', 'home-filter-time', TIMES,
        (k: string) => this.vm.timeFilter === k,
        (k: string) => this.vm.setTime(k as TimeKey))

      // Last result card
      this.LastResultCard()

      // Quick check-in row
      Row() {
        Column({ alignItems: HorizontalAlign.Start }) {
          Text('快速记录')
            .fontSize(16)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.espresso)
          Text('随手记下今天吃了什么')
            .fontSize(13)
            .fontColor(Theme.stone)
            .margin({ top: 3 })
        }
        .alignItems(HorizontalAlign.Start)
        .layoutWeight(1)

        Button() {
          SvgIcon({ variant: 'add', iconSize: 22 })
        }
        .id('home-quick-checkin-button')
        .type(ButtonType.Circle)
        .width(46)
        .height(46)
        .linearGradient(BrandGradient.coral)
        .shadow(Theme.shadowFloat)
        .onClick(() => this.openCheckin(''))
      }
      .width('100%')
      .padding(18)
      .borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBg)
      .shadow(Theme.shadowCard)
      .alignItems(VerticalAlign.Center)
    }
    .width('100%')
    .height('100%')
  }

  private openWheelLabel(): string {
    return '开始转盘';
  }

  @Builder
  FilterSection(label: string, sectionId: string, items: string[],
    isActive: (k: string) => boolean, onTap: (k: string) => void) {
    Column({ alignItems: HorizontalAlign.Start }) {
      Text(label)
        .fontSize(14)
        .fontWeight(FontWeight.Medium)
        .fontColor(Theme.espresso)
        .margin({ bottom: 12 })
      Flex({ wrap: FlexWrap.Wrap }) {
        ForEach(items, (k: string) => {
          Text(k)
            .id(sectionId)
            .fontSize(13)
            .fontWeight(FontWeight.Medium)
            .fontColor(isActive(k) ? '#FFFFFF' : Theme.stone)
            .padding({ left: 16, right: 16, top: 10, bottom: 10 })
            .borderRadius(Theme.radiusChip)
            .backgroundColor(isActive(k) ? Theme.coral : Theme.chipBg)
            .border({ width: 1, color: isActive(k) ? Theme.coral : Theme.borderSoft })
            .margin({ right: 10, bottom: 10 })
            .onClick(() => onTap(k))
        }, (k: string) => k)
      }
      .width('100%')
    }
    .width('100%')
    .alignItems(HorizontalAlign.Start)
    .margin({ bottom: 20 })
  }

  @Builder
  LastResultCard() {
    if (this.vm.lastResult) {
      Column() {
        Row() {
          Text('上次结果')
            .fontSize(18)
            .fontWeight(FontWeight.Bold)
            .fontColor(Theme.espresso)
            .layoutWeight(1)
          Text('转盘推荐')
            .fontSize(11)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.coral)
            .padding({ left: 10, right: 10, top: 5, bottom: 5 })
            .borderRadius(Theme.radiusChip)
            .backgroundColor(Theme.peach)
        }
        .width('100%')
        .margin({ bottom: 14 })

        Text(this.vm.lastResult!.name)
          .fontSize(22)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.espresso)
          .margin({ bottom: 10 })

        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach(this.vm.lastResult!.tags, (t: string) => {
            Text(t)
              .fontSize(12)
              .fontWeight(FontWeight.Medium)
              .fontColor('#FFFFFF')
              .padding({ left: 12, right: 12, top: 6, bottom: 6 })
              .borderRadius(Theme.radiusChip)
              .backgroundColor(tagColor(t))
              .margin({ right: 8, bottom: 8 })
          }, (t: string) => t)
        }
        .width('100%')
        .margin({ bottom: 14 })

        Row() {
          Button() {
            Row() {
              SvgIcon({ variant: 'share', iconSize: 18 })
              Text('分享')
                .fontSize(15)
                .fontWeight(FontWeight.Medium)
                .fontColor(Theme.coral)
                .margin({ left: 6 })
            }
          }
          .type(ButtonType.Capsule)
          .layoutWeight(1)
          .height(48)
          .backgroundColor(Theme.cardBg)
          .border({ width: 1.5, color: Theme.coral })
          .onClick(() => this.openShare())

          Blank().width(10)

          Button() {
            Row() {
              SvgIcon({ variant: 'logMeal', iconSize: 18 })
              Text('打卡')
                .fontSize(15)
                .fontWeight(FontWeight.Medium)
                .fontColor(Theme.coral)
                .margin({ left: 6 })
            }
          }
          .id('home-quick-checkin-button')
          .type(ButtonType.Capsule)
          .layoutWeight(1)
          .height(48)
          .backgroundColor(Theme.cardBg)
          .border({ width: 1.5, color: Theme.coral })
          .onClick(() => this.openCheckin(this.vm.lastResult ? this.vm.lastResult.name : ''))
        }
        .width('100%')
      }
      .id('home-last-result-card')
      .width('100%')
      .padding(22)
      .borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBg)
      .shadow(Theme.shadowCard)
      .alignItems(HorizontalAlign.Start)
    } else {
      Column() {
        Text('还没有结果')
          .fontSize(16)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.stone)
        Text('点上方「开始转盘」让转盘帮你决定吧')
          .fontSize(13)
          .fontColor(Theme.stone)
          .margin({ top: 6 })
      }
      .id('home-no-result-yet')
      .width('100%')
      .padding(28)
      .borderRadius(Theme.radiusCard)
      .backgroundColor('rgba(255,255,255,0.72)')
      .border({ width: 1.5, color: 'rgba(45,42,38,0.14)', style: BorderStyle.Dashed })
      .alignItems(HorizontalAlign.Center)
      .margin({ bottom: 20 })
    }
  }
}

