// Wheel page — full-screen spinner. Reproduces page-wheel-page.html.
import { AppViewModel } from '../viewmodel/AppViewModel';
import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { tagColor } from '../data/DishLibrary';
import { WheelSpinResult } from '../model/Models';

const QUICK_FILTERS: string[] = ['辣的', '清淡', '快手', '健康', '治愈系'];

@Component
export struct WheelPage {
  vm: AppViewModel;
  onBack: () => void = () => {};
  onAccept: (dishName: string) => void = (_dishName: string) => {};

  @State rotation: number = 0;
  @State spinning: boolean = false;
  @State quickActive: string = '';

  build() {
    Column() {
      // Top bar
      Row() {
        Button() {
          SvgIcon({ variant: 'back', iconSize: 20 })
        }
        .id('wheel-back-button')
        .type(ButtonType.Circle)
        .width(40)
        .height(40)
        .backgroundColor(Theme.cardBg)
        .shadow(Theme.shadowCard)
        .onClick(() => this.onBack())

        Text('美食转盘')
          .fontSize(20)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.espresso)
          .layoutWeight(1)
          .textAlign(TextAlign.Center)
        Blank().width(40)
      }
      .width('100%')
      .margin({ bottom: 20 })

      // Wheel stage
      Stack({ alignContent: Alignment.Top }) {
        Image($rawfile('icon_Food-Decision-Wheel.svg'))
          .id('wheel-canvas')
          .width(300)
          .height(300)
          .objectFit(ImageFit.Contain)
          .rotate({ angle: this.rotation })

        Button() {
          Text('GO')
            .fontSize(18)
            .fontWeight(FontWeight.Bold)
            .fontColor('#FFFFFF')
        }
        .id('wheel-spin-trigger')
        .type(ButtonType.Circle)
        .width(84)
        .height(84)
        .linearGradient(BrandGradient.coral)
        .border({ width: 5, color: '#FFFFFF' })
        .shadow(Theme.shadowFloat)
        .enabled(!this.spinning)
        .onClick(() => this.doSpin())
      }
      .width('100%')
      .height(320)
      .alignContent(Alignment.Center)
      .margin({ bottom: 22 })

      // Pointer
      SvgIcon({ variant: 'wheelPointer', iconSize: 28 })
        .position({ x: '50%', y: 10 })
        .markAnchor({ x: '50%', y: 0 })

      // Result panel
      Column() {
        Text('转盘推荐')
          .fontSize(13)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.stone)
          .margin({ bottom: 8 })

        Text(this.resultName())
          .id('wheel-result-name')
          .fontSize(28)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.espresso)
          .margin({ bottom: 12 })

        Flex({ wrap: FlexWrap.Wrap, justifyContent: FlexAlign.Center }) {
          ForEach(this.vm.wheelResultTags, (t: string) => {
            Text(t)
              .fontSize(12)
              .fontWeight(FontWeight.Medium)
              .fontColor('#FFFFFF')
              .padding({ left: 14, right: 14, top: 7, bottom: 7 })
              .borderRadius(Theme.radiusChip)
              .backgroundColor(tagColor(t))
              .margin({ right: 8, bottom: 8 })
          }, (t: string) => t)
        }
        .width('100%')
        .margin({ bottom: 18 })

        Row() {
          Button() {
            Row() {
              SvgIcon({ variant: 'accept', iconSize: 20 })
              Text('就选它')
                .fontSize(16)
                .fontWeight(FontWeight.Medium)
                .fontColor('#FFFFFF')
                .margin({ left: 8 })
            }
          }
          .id('wheel-accept-button')
          .type(ButtonType.Capsule)
          .layoutWeight(1)
          .height(52)
          .linearGradient(BrandGradient.coral)
          .shadow(Theme.shadowFloat)
          .enabled(this.vm.wheelState === 'result')
          .onClick(() => this.onAccept(this.vm.wheelResultName))

          Blank().width(12)

          Button() {
            Row() {
              SvgIcon({ variant: 'retry', iconSize: 18 })
              Text('再转一次')
                .fontSize(15)
                .fontWeight(FontWeight.Medium)
                .fontColor(Theme.coral)
                .margin({ left: 6 })
            }
          }
          .id('wheel-retry-button')
