// Wheel page — full-screen spinner. Reproduces page-wheel-page.html.
import { AppViewModel } from '../viewmodel/AppViewModel';
import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { tagColor } from '../data/DishLibrary';
import { WheelSpinResult } from '../model/Models';

const QUICK_FILTERS: string[] = ['辣的', '清淡', '快手', '健康', '治愈系'];

@Component
export struct WheelPage {
  vm: AppViewModel;
  onBack: () => void = () => {};
  onAccept: (dishName: string) => void = (_dishName: string) => {};

  @State rotation: number = 0;
  @State spinning: boolean = false;
  @State quickActive: string = '';

  build() {
    Column() {
      // Top bar
      Row() {
        Button() {
          SvgIcon({ variant: 'back', iconSize: 20 })
        }
        .id('wheel-back-button')
        .type(ButtonType.Circle)
        .width(40)
        .height(40)
        .backgroundColor(Theme.cardBg)
        .shadow(Theme.shadowCard)
        .onClick(() => this.onBack())

        Text('美食转盘')
          .fontSize(20)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.espresso)
          .layoutWeight(1)
          .textAlign(TextAlign.Center)
        Blank().width(40)
      }
      .width('100%')
      .margin({ bottom: 20 })

      // Wheel stage
      Stack({ alignContent: Alignment.Top }) {
        Image($rawfile('icon_Food-Decision-Wheel.svg'))
          .id('wheel-canvas')
          .width(300)
          .height(300)
          .objectFit(ImageFit.Contain)
          .rotate({ angle: this.rotation })

        Button() {
          Text('GO')
            .fontSize(18)
            .fontWeight(FontWeight.Bold)
            .fontColor('#FFFFFF')
        }
        .id('wheel-spin-trigger')
        .type(ButtonType.Circle)
        .width(84)
        .height(84)
        .linearGradient(BrandGradient.coral)
        .border({ width: 5, color: '#FFFFFF' })
        .shadow(Theme.shadowFloat)
        .enabled(!this.spinning)
        .onClick(() => this.doSpin())
      }
      .width('100%')
      .height(320)
      .alignContent(Alignment.Center)
      .margin({ bottom: 22 })

      // Pointer
      SvgIcon({ variant: 'wheelPointer', iconSize: 28 })
        .position({ x: '50%', y: 10 })
        .markAnchor({ x: '50%', y: 0 })

      // Result panel
      Column() {
        Text('转盘推荐')
          .fontSize(13)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.stone)
          .margin({ bottom: 8 })

        Text(this.resultName())
          .id('wheel-result-name')
          .fontSize(28)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.espresso)
          .margin({ bottom: 12 })

        Flex({ wrap: FlexWrap.Wrap, justifyContent: FlexAlign.Center }) {
          ForEach(this.vm.wheelResultTags, (t: string) => {
            Text(t)
              .fontSize(12)
              .fontWeight(FontWeight.Medium)
              .fontColor('#FFFFFF')
              .padding({ left: 14, right: 14, top: 7, bottom: 7 })
              .borderRadius(Theme.radiusChip)
              .backgroundColor(tagColor(t))
              .margin({ right: 8, bottom: 8 })
          }, (t: string) => t)
        }
        .width('100%')
        .margin({ bottom: 18 })

        Row() {
          Button() {
            Row() {
              SvgIcon({ variant: 'accept', iconSize: 20 })
              Text('就选它')
                .fontSize(16)
                .fontWeight(FontWeight.Medium)
                .fontColor('#FFFFFF')
                .margin({ left: 8 })
            }
          }
          .id('wheel-accept-button')
          .type(ButtonType.Capsule)
          .layoutWeight(1)
          .height(52)
          .linearGradient(BrandGradient.coral)
          .shadow(Theme.shadowFloat)
          .enabled(this.vm.wheelState === 'result')
          .onClick(() => this.onAccept(this.vm.wheelResultName))

          Blank().width(12)

          Button() {
            Row() {
              SvgIcon({ variant: 'retry', iconSize: 18 })
              Text('再转一次')
                .fontSize(15)
                .fontWeight(FontWeight.Medium)
                .fontColor(Theme.coral)
                .margin({ left: 6 })
            }
          }
          .id('wheel-retry-button')
          .type(ButtonType.Capsule)
          .layoutWeight(1)
          .height(48)
          .backgroundColor(Theme.cardBg)
          .border({ width: 1.5, color: Theme.coral })
          .enabled(!this.spinning)
          .onClick(() => this.doSpin())
        }
        .width('100%')
      }
      .width('100%')
      .padding(26)
      .borderRadius(Theme.radiusCardLarge)
      .backgroundColor(Theme.cardBg)
      .shadow(Theme.shadowCard)
      .alignItems(HorizontalAlign.Center)
      .margin({ bottom: 20 })

      // Quick filters
      Column({ alignItems: HorizontalAlign.Start }) {
        Text('快速筛选')
          .fontSize(14)
          .fontWeight(FontWeight.Medium)
          .fontColor(Theme.espresso)
          .margin({ bottom: 12 })
        Flex({ wrap: FlexWrap.Wrap }) {
          ForEach(QUICK_FILTERS, (k: string) => {
            Text(k)
              .id('wheel-filter-chip-group')
              .fontSize(13)
              .fontWeight(FontWeight.Medium)
              .fontColor(this.quickActive === k ? '#FFFFFF' : Theme.stone)
              .padding({ left: 16, right: 16, top: 10, bottom: 10 })
              .borderRadius(Theme.radiusChip)
              .backgroundColor(this.quickActive === k ? Theme.coral : Theme.chipBg)
              .border({ width: 1, color: this.quickActive === k ? Theme.coral : Theme.borderSoft })
              .margin({ right: 10, bottom: 10 })
              .onClick(() => this.toggleQuick(k))
          }, (k: string) => k)
        }
        .width('100%')
      }
      .width('100%')
      .alignItems(HorizontalAlign.Start)
    }
    .width('100%')
    .height('100%')
  }

  private resultName(): string {
    return this.vm.wheelState === 'result' && this.vm.wheelResultName.length > 0
      ? this.vm.wheelResultName
      : '点 GO 开始转盘';
  }

  private toggleQuick(k: string): void {
    this.quickActive = this.quickActive === k ? '' : k;
    this.vm.toggleWheelFilter(k);
  }

  private doSpin(): void {
    if (this.spinning) {
      return;
    }
    let result: WheelSpinResult = this.vm.computeSpin();
    this.spinning = true;
    this.vm.setWheelState('spinning');
    animateTo({
      duration: 3200,
      curve: Curve.Decelerate,
      onFinish: () => {
        this.spinning = false;
        this.vm.commitSpin(result);
      },
    }, () => {
      this.rotation = result.finalAngle;
    });
  }
}

