// Fridge page — ingredient-based recommendation. Reproduces page-fridge-page.html.
import { AppViewModel } from '../viewmodel/AppViewModel';
import { Theme, BrandGradient } from '../common/Theme';
import { SvgIcon } from '../common/SvgIcon';
import { tagColor } from '../data/DishLibrary';

@Component
export struct FridgePage {
  vm: AppViewModel;
  openCheckin: (dish: string) => void = (_dish: string) => {};

  @State inputText: string = '';

  build() {
    Column() {
      // Header
      Column({ alignItems: HorizontalAlign.Start }) {
        Text('我的冰箱')
          .fontSize(28)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.espresso)
        Text('添加食材，看看能做点什么好吃的。')
          .fontSize(15)
          .fontColor(Theme.stone)
          .margin({ top: 6 })
      }
      .width('100%')
      .alignItems(HorizontalAlign.Start)
      .margin({ bottom: 20 })

      // Input card
      Column() {
        Row() {
          TextInput({ text: this.inputText, placeholder: '例如：鸡蛋、番茄、牛肉...' })
            .id('fridge-ingredient-input')
            .layoutWeight(1)
            .height(50)
            .fontSize(16)
            .fontColor(Theme.charcoal)
            .borderRadius(Theme.radiusInput)
            .backgroundColor(Theme.cardBg)
            .border({ width: 1.5, color: Theme.borderSoft })
            .padding({ left: 16, right: 16 })
            .onChange((v: string) => { this.inputText = v; })

          Blank().width(10)

          Button() {
            SvgIcon({ variant: 'addFridge', iconSize: 22 })
          }
          .id('fridge-add-button')
          .type(ButtonType.Normal)
          .width(50)
          .height(50)
          .borderRadius(Theme.radiusInput)
          .linearGradient(BrandGradient.coral)
          .shadow(Theme.shadowFloat)
          .onClick(() => this.confirmAdd())
        }
        .width('100%')

        // Ingredient chips
        if (this.vm.ingredients.length === 0) {
          Text('还没有添加食材')
            .fontSize(13)
            .fontColor(Theme.stone)
            .margin({ top: 14 })
            .width('100%')
            .textAlign(TextAlign.Center)
        } else {
          Flex({ wrap: FlexWrap.Wrap }) {
            ForEach(this.vm.ingredients, (name: string) => {
              Row() {
                Text(name)
                  .fontSize(14)
                  .fontWeight(FontWeight.Medium)
                  .fontColor(Theme.espresso)
                Button() {
                  SvgIcon({ variant: 'remove', iconSize: 14 })
                }
                .id('fridge-remove-button')
                .type(ButtonType.Normal)
                .width(20)
                .height(20)
                .backgroundColor(Color.Transparent)
                .margin({ left: 6 })
                .onClick(() => this.vm.removeIngredient(name))
              }
              .id(`fridge-ingredient-${name}`)
              .padding({ left: 12, right: 10, top: 8, bottom: 8 })
              .borderRadius(Theme.radiusChip)
              .backgroundColor(Theme.peach)
              .margin({ right: 10, bottom: 10 })
              .alignItems(VerticalAlign.Center)
            }, (name: string) => name)
          }
          .width('100%')
          .margin({ top: 16 })
        }
      }
      .width('100%')
      .padding(20)
      .borderRadius(Theme.radiusCard)
      .backgroundColor(Theme.cardBg)
      .shadow(Theme.shadowCard)
      .margin({ bottom: 22 })

      // Matched dishes section header
      Row() {
        Text('推荐菜品')
          .fontSize(18)
          .fontWeight(FontWeight.Bold)
          .fontColor(Theme.espresso)
          .layoutWeight(1)
        Row() {
          Text(`${this.vm.matchedDishes.length} 个匹配`)
            .fontSize(13)
            .fontColor(Theme.stone)
            .padding({ left: 10, right: 10, top: 5, bottom: 5 })
            .borderRadius(Theme.radiusChip)
            .backgroundColor(Theme.cardBg)
          Blank().width(10)
          Text('清空')
            .id('fridge-clear-all-button')
            .fontSize(13)
            .fontWeight(FontWeight.Medium)
            .fontColor(Theme.coral)
            .onClick(() => this.vm.clearIngredients())
        }
        .alignItems(VerticalAlign.Center)
      }
      .width('100%')
      .margin({ bottom: 14 })

      // Matched dish list / empty states
      if (this.vm.ingredients.length === 0) {
        this.EmptyState('fridge-empty-state', '先添加几样食材', '我们会用冰箱里的食材为你匹配菜品。')
      } else if (this.vm.matchedDishes.length === 0) {
        this.EmptyState('fridge-no-match-state', '暂无匹配菜品', '试试添加其他常见食材，比如鸡蛋、番茄。')
      } else {
        List({ space: 14 }) {
          ForEach(this.vm.matchedDishes, (m: MatchedDishView) => {
            ListItem() {
              Row() {
                Column() {
                  SvgIcon({ variant: m.thumbVariant, iconSize: 28 })
                }
                .width(56)
                .height(56)
                .borderRadius(Theme.radiusInput)
                .linearGradient({ angle: 135, direction: GradientDirection.RightTop,
                  colors: [['#FFE8D9', 0.0], ['#FFD4BD', 1.0]] } as LinearGradient)
                .justifyContent(FlexAlign.Center)
                .alignItems(HorizontalAlign.Center)

                Blank().width(14)

                Column({ alignItems: HorizontalAlign.Start }) {
                  Text(m.dishName)
                    .fontSize(17)
                    .fontWeight(FontWeight.Bold)
                    .fontColor(Theme.espresso)
                    .margin({ bottom: 6 })
                  Text(m.meta)
                    .fontSize(13)
                    .fontColor(Theme.stone)
                    .margin({ bottom: 8 })
                  Row() {
                    Text(m.matchLabel)
                      .fontSize(11)
                      .fontWeight(FontWeight.Medium)
                      .fontColor('#FFFFFF')
                      .padding({ left: 10, right: 10, top: 5, bottom: 5 })
                      .borderRadius(Theme.radiusChip)
                      .backgroundColor(m.fullyMatched ? Theme.sage : Theme.comfortBrown)
                      .margin({ right: 6 })
                    ForEach(m.tags, (t: string) => {
                      Text(t)
                        .fontSize(11)
                        .fontWeight(FontWeight.Medium)
                        .fontColor('#FFFFFF')
                        .padding({ left: 10, right: 10, top: 5, bottom: 5 })
                        .borderRadius(Theme.radiusChip)
                        .backgroundColor(tagColor(t))
                        .margin({ right: 6 })
                    }, (t: string) => t)
                  }
                  .alignItems(VerticalAlign.Center)
                }
                .alignItems(HorizontalAlign.Start)
                .layoutWeight(1)

                // Quick check-in from a matched dish
                Button() {
                  SvgIcon({ variant: 'logMeal', iconSize: 18 })
                }
                .type(ButtonType.Circle)
                .width(40)
                .height(40)
                .backgroundColor(Theme.peach)
                .onClick(() => this.openCheckin(m.dishName))
              }
              .id(`fridge-dish-${m.dishId}`)
              .width('100%')
              .padding(18)
              .borderRadius(Theme.radiusCard)
              .backgroundColor(Theme.cardBg)
              .shadow(Theme.shadowCard)
              .alignItems(VerticalAlign.Center)
            }
          }, (m: MatchedDishView) => m.dishId)
        }
        .width('100%')
        .layoutWeight(1)
        .scrollBar(BarState.Off)
      }
    }
    .width('100%')
    .height('100%')
  }

  private confirmAdd(): void {
    const v = this.inputText.trim();
    if (v.length === 0) {
      return;
    }
    this.vm.addIngredient(v);
    this.inputText = '';
  }

  @Builder
  EmptyState(idValue: string, title: string, desc: string) {
    Column() {
      Text(title)
        .fontSize(16)
        .fontWeight(FontWeight.Medium)
        .fontColor(Theme.stone)
      Text(desc)
        .fontSize(13)
        .fontColor(Theme.stone)
        .margin({ top: 6 })
        .textAlign(TextAlign.Center)
    }
    .id(idValue)
    .width('100%')
    .padding(40)
    .borderRadius(Theme.radiusCard)
    .backgroundColor('rgba(255,255,255,0.72)')
    .border({ width: 1.5, color: 'rgba(45,42,38,0.14)', style: BorderStyle.Dashed })
    .alignItems(HorizontalAlign.Center)
  }
}

// View-model projection for a matched dish row (keeps the ForEach typed).
export interface MatchedDishView {
  dishId: string;
  dishName: string;
  meta: string;
  matchLabel: string;
  fullyMatched: boolean;
  tags: string[];
  thumbVariant: string;
}

